 68 /// Given an icmp instruction, return true if any use of this comparison is a
 69 /// branch on sign bit comparison.
 70 static bool hasBranchUse(ICmpInst &I) {
 71   for (auto *U : I.users())
 72     if (isa<BranchInst>(U))
 73       return true;
 74   return false;
